@implements IAsyncDisposable
@inject IJSRuntime JS

@ChildContent

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./Components/UserActivityTracker.razor.js");
        await _module.InvokeVoidAsync("initialize", _dotNetRef, TimeoutSeconds);
    }

    [JSInvokable]
    public async Task OnIdleTriggered() => await OnIdle.InvokeAsync();

    [JSInvokable]
    public async Task OnActiveTriggered() => await OnActive.InvokeAsync();

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
            }
            catch (JSDisconnectedException) { }
            try
            {
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

let dotNetRef = null;
let timeoutId = null;
let isIdle = false;

const events = ["mousemove", "keydown", "click", "scroll"];

function handleActivity() {
    if (timeoutId !== null) {
        clearTimeout(timeoutId);
    }

    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync("OnActiveTriggered");
    }

    timeoutId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleTriggered");
    }, timeoutSeconds * 1000);
}

let timeoutSeconds = 300;

export function initialize(ref, seconds) {
    dotNetRef = ref;
    timeoutSeconds = seconds;
    isIdle = false;
    timeoutId = null;

    for (const event of events) {
        document.addEventListener(event, handleActivity, { passive: true });
    }

    // Start the initial idle timer
    timeoutId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleTriggered");
    }, timeoutSeconds * 1000);
}

export function dispose() {
    for (const event of events) {
        document.removeEventListener(event, handleActivity);
    }

    if (timeoutId !== null) {
        clearTimeout(timeoutId);
        timeoutId = null;
    }

    dotNetRef = null;
    isIdle = false;
}

